chrome.runtime.onInstalled.addListener(e=>{console.log("[PulseWrite] 🎉 Extension installed!",e.reason),e.reason==="install"&&(chrome.storage.sync.set({pulsewrite_settings:{model:"llama-3.1-70b-versatile",tone:"professional",postLength:"medium",language:"en",onboardingComplete:!1}}),console.log("[PulseWrite] Default settings saved to chrome.storage.sync"))});chrome.runtime.onMessage.addListener((e,s,t)=>{switch(console.log("[PulseWrite] Message received:",e,"from:",s.tab?.url),e.type){case"OPEN_PULSEWRITE":console.log("[PulseWrite] Open request from content script"),t({status:"ok"});break;case"GENERATE_IDEAS":console.log("[PulseWrite] Generate ideas request:",e.payload),t({status:"pending",message:"Generation not yet implemented"});break;case"GET_SETTINGS":return chrome.storage.sync.get("pulsewrite_settings",o=>{t({settings:o.pulsewrite_settings})}),!0;default:console.log("[PulseWrite] Unknown message type:",e.type),t({status:"error",message:"Unknown message type"})}});console.log("[PulseWrite] 🔧 Background service worker started");
